8030     [[fallthrough]];
8031   case FCmpInst::FCMP_OGT:
8032   case FCmpInst::FCMP_OLT:
8033   case FCmpInst::FCMP_ONE:
8034   case FCmpInst::FCMP_UEQ:
8035   case FCmpInst::FCMP_UGE:
8036   case FCmpInst::FCMP_ULE:
